import{c as e,Q as t,j as d,m as a}from"./chunks/framework.D9IbVcwA.js";const h=JSON.parse('{"title":"004-boot-load-mini-kernel-c-1 · 内核加载 (C)","description":"","frontmatter":{"title":"004-boot-load-mini-kernel-c-1 · 内核加载 (C)"},"headers":[],"relativePath":"hands-on/004-boot-load-mini-kernel-c-1.md","filePath":"hands-on/004-boot-load-mini-kernel-c-1.md","lastUpdated":1779686691000}'),c={name:"hands-on/004-boot-load-mini-kernel-c-1.md"};function n(r,o,i,s,l,p){return t(),d("div",null,[...o[0]||(o[0]=[a(`<h1 id="_004-c-动手篇-上-bootinfo-填充与高半核跳转" tabindex="-1">004-C 动手篇（上）：BootInfo 填充与高半核跳转 <a class="header-anchor" href="#_004-c-动手篇-上-bootinfo-填充与高半核跳转" aria-label="Permalink to &quot;004-C 动手篇（上）：BootInfo 填充与高半核跳转&quot;">​</a></h1><blockquote><p>本章完成后的可见效果：debugcon 日志中在 <code>OPL</code> 之后出现 <code>J</code> 字符，紧接着出现 <code>123G4===CPPGC1V123B===END</code>，表示 Bootloader 成功填充 BootInfo 并跳转到 Mini Kernel 的 C++ 入口</p><p>前置要求：已完成 <code>004_boot_load_mini_kernel_B</code>，理解 Mini Kernel 的磁盘加载和 Real Mode 下的 E820/VESA 信息采集</p></blockquote><hr><h2 id="导语" tabindex="-1">导语 <a class="header-anchor" href="#导语" aria-label="Permalink to &quot;导语&quot;">​</a></h2><p>上一章我们在 Real Mode 下把 Mini Kernel 的完整二进制从磁盘读到了物理地址 0x20000，然后一路切进 Long Mode 打出了那个熟悉的 <code>L</code>。但说实话，此时此刻 CPU 跑的还是 Bootloader 的代码——内核虽然已经在内存里躺着了，可我们连碰都没碰它。更关键的是，之前 E820 探测的内存映射、VESA 获取的帧缓冲信息，全都散落在 0x5000 和 0x6400 这两块低内存区域，内核压根不知道它们的存在。</p><p>这一章我们要做的事情，就是在这两块碎片和内核之间搭一座桥。具体来说：进入 Long Mode 之后，我们把所有零散的引导信息打包成一个固定格式的 BootInfo 结构体，写到物理地址 0x7000；然后在页表里新增一组高半核映射（Higher-Half Mapping），让内核的虚拟入口地址 0xFFFFFFFF80020000 指向和物理地址 0x20000 相同的那块物理内存；最后把 BootInfo 的地址塞进 <code>%rdi</code>，一记 <code>jmp *%rax</code> 跳过去，从此 Bootloader 功成身退，内核接管一切。</p><p>听起来逻辑很干净对吧？但魔鬼全在细节里——BootInfo 的结构布局要和 C 头文件严格对齐、高半核的 PML4/PDPT 索引要算对、从 VESA 临时缓冲区搬运帧缓冲字段时字节宽度和偏移差一拍都不行。而且这一章还涉及到一个跨编译环境的关键问题：BootInfo 的头文件同时被 Bootloader（32 位 C）和内核（64 位 C++）include，两边对 <code>static_assert</code> 的关键字叫法都不一样——这种细节漏了编译直接炸。下面我们一步一步来。</p><hr><h2 id="低-1mb-内存地图" tabindex="-1">低 1MB 内存地图 <a class="header-anchor" href="#低-1mb-内存地图" aria-label="Permalink to &quot;低 1MB 内存地图&quot;">​</a></h2><p>动手之前先快速回顾一下当前的低 1MB 内存布局，因为 BootInfo 放在哪里、数据从哪里来，完全取决于这个布局。从 0x5000 到 0x7C00 之间的区域已经相当拥挤了——E820 缓冲区占了 0x5000 起始的一段，VESA 帧缓冲信息在 0x6400，DAP 在 0x7B00，MBR 在 0x7C00，Stage2 从 0x8000 开始。现在我们要在这个夹缝里再塞一个 824 字节的 BootInfo，选位置的时候必须避开所有已占用的区域。选定的位置是 0x7000——它到下一个占用区域（0x7B00 的 DAP）之间有约 2KB 的空间，而 BootInfo 只需要 824 字节（约 0x338），放得下。</p><hr><h2 id="概念精讲" tabindex="-1">概念精讲 <a class="header-anchor" href="#概念精讲" aria-label="Permalink to &quot;概念精讲&quot;">​</a></h2><h3 id="bootinfo-bootloader-和内核之间的-交接清单" tabindex="-1">BootInfo：Bootloader 和内核之间的&quot;交接清单&quot; <a class="header-anchor" href="#bootinfo-bootloader-和内核之间的-交接清单" aria-label="Permalink to &quot;BootInfo：Bootloader 和内核之间的&quot;交接清单&quot;&quot;">​</a></h3><p>你可以把 BootInfo 想象成一份搬家时留给新房客的清单——上面写着&quot;电视机在哪、电表在哪、仓库有多大、哪些房间能用&quot;。Bootloader 是旧房客，跑完就走了；内核是新房客，进门第一件事就是看这份清单，搞清楚环境状况，然后才开始干活。</p><p>这份清单放在物理地址 0x7000，总共 824 字节，<code>__attribute__((packed))</code> 压缩过，没有任何填充字节。它的前三个字段是内核自身的信息：入口点的虚拟地址（高半核地址，8 字节）、物理加载基地址（8 字节）、以及内核大小（8 字节）。紧接着是帧缓冲区的六个字段——物理地址（8 字节）、宽度（4 字节）、高度（4 字节）、每行字节数 pitch（4 字节）、色深 bpp（4 字节）。然后是内存映射：条目数量（4 字节）、一个 4 字节对齐填充、最多 32 条 E820 记录，每条 24 字节（base 8 字节 + length 8 字节 + type 4 字节 + acpi 4 字节），总计 768 字节。</p><p>算一下：3 个 uint64_t 加 fb_addr 是 32 字节，5 个 uint32_t 是 20 字节，mmap_count 加 _pad 是 8 字节，32 条 mmap 是 768 字节——加起来正好 824。我们在头文件里放一个 <code>static_assert(sizeof(BootInfo) == 824)</code> 作为编译期断言，谁改了结构体编译直接报错，而不是跑到运行时数据错位才抓狂。</p><p>这里有一个 C/C++ 兼容性的小坑值得提一嘴：<code>static_assert</code> 在 C++ 里是关键字，但在 C 里叫 <code>_Static_assert</code>。因为 <code>boot_info.h</code> 这个头文件同时被 Bootloader 的汇编预处理和内核的 C++ 代码包含，所以需要用 <code>#if defined(__cplusplus)</code> 做条件编译，两边各用各的写法。别小看这个细节——如果你只写了 <code>static_assert</code>，用纯 C 编译 Bootloader 的时候直接就炸了。</p><h3 id="高半核映射-为什么内核要住在地址空间的-阁楼-里" tabindex="-1">高半核映射：为什么内核要住在地址空间的&quot;阁楼&quot;里 <a class="header-anchor" href="#高半核映射-为什么内核要住在地址空间的-阁楼-里" aria-label="Permalink to &quot;高半核映射：为什么内核要住在地址空间的&quot;阁楼&quot;里&quot;">​</a></h3><p>x86-64 的 64 位虚拟地址并不是真的 64 位都用上了。硬件只实现了 48 位的有效地址，剩余的高 16 位（bit 48 到 bit 63）必须全是 0 或全是 1——这叫&quot;规范地址&quot;（Canonical Address）。全 0 的范围是 0x0000000000000000 到 0x00007FFFFFFFFFFF，这是用户空间；全 1 的范围是 0xFFFF800000000000 到 0xFFFFFFFFFFFFFFFF，这是内核空间。我们选的内核基址 0xFFFFFFFF80000000 就在这个内核空间的上半段，所以叫&quot;高半核&quot;（Higher-Half Kernel）。</p><p>为什么要费这个劲？最直接的好处是：内核占据高地址空间后，整个低地址区域从 0 开始的一段就可以完整地给用户程序用，不需要在每次创建用户进程时费心绕开内核占用的那段低地址。Linux、Windows、macOS 的内核全都是高半核设计——这不是偶然，而是地址空间管理的最佳实践。</p><p>在我们的四级页表结构里（PML4 -&gt; PDPT -&gt; PD -&gt; Page），虚拟地址 0xFFFFFFFF80020000 的索引拆解如下：PML4 索引取 bit 47:39，也就是 511（0x1FF）；PDPT 索引取 bit 38:30，算出来是 510（0x1FE）；PD 索引取 bit 29:21，得 0（0x000）。所以我们需要在 PML4 的第 511 个条目里填入 PDPT 的物理地址，在 PDPT 的第 510 个条目里填入 PD 的物理地址。PD 的第 0 个条目已经在之前设置了——它用 2MB 大页映射了物理地址 0~2MB 的范围，而 0x20000 正好落在这个范围内。这样一来，身份映射（0x20000 -&gt; 0x20000）和高半核映射（0xFFFFFFFF80020000 -&gt; 0x20000）指向同一块物理内存，同一份内核代码可以通过两套地址访问到。Bootloader 跳转用高半核地址，内核从此就&quot;住进了阁楼&quot;。</p><p>Intel SDM Vol. 3A 第 4 章（Paging）对四级页表结构的索引拆解有完整的说明，Virtual Address 的 bit 划分和每一级页表的物理布局都写得非常清楚。</p><p>值得一提的是这里有一个规范细节需要注意：x86-64 的虚拟地址必须是 canonical address，即 bits 63:48 必须是 bit 47 的符号扩展。<code>0xFFFFFFFF80020000</code> 的 bit 47 = 1，所以 bits 63:48 全部是 1——这是合法的 canonical address。如果你尝试访问一个非 canonical 地址（比如 <code>0x0000800000000000</code>，bit 47 = 0 但 bit 48 = 1），CPU 会直接触发 General Protection Fault，连页表查询都不会做。这个约束来自 x86-64 架构的虚拟地址设计——Intel SDM Vol. 3A Section 3.3.7 对此有详细说明。</p><hr><h2 id="动手实现" tabindex="-1">动手实现 <a class="header-anchor" href="#动手实现" aria-label="Permalink to &quot;动手实现&quot;">​</a></h2><h3 id="step-1-更新-boot-info-h——c-c-兼容的-static-assert-和正确的-bootinfo-尺寸" tabindex="-1">Step 1: 更新 boot_info.h——C/C++ 兼容的 static_assert 和正确的 BootInfo 尺寸 <a class="header-anchor" href="#step-1-更新-boot-info-h——c-c-兼容的-static-assert-和正确的-bootinfo-尺寸" aria-label="Permalink to &quot;Step 1: 更新 boot_info.h——C/C++ 兼容的 static_assert 和正确的 BootInfo 尺寸&quot;">​</a></h3><p><strong>目标</strong>：确保 <code>boot/boot_info.h</code> 这个头文件既能被 C++ 编译器（编译内核），又能被 C 编译器（编译 Bootloader 相关工具）正常处理，同时保证 BootInfo 的尺寸断言值是正确的 824。</p><p><strong>设计思路</strong>：上一章定义 BootInfo 的时候可能 <code>static_assert</code> 只写了 C++ 的形式，或者 BootInfo 的 size 计算值不是 824。现在我们要修复这两个问题。<code>static_assert</code> 是 C++11 引入的关键字，对应的 C11 标准写法是 <code>_Static_assert</code>，两者语法略有差异（C 版本需要把字符串放在第二个参数位置）。通过 <code>#if defined(__cplusplus)</code> 做分支选择就能两边都照顾到。BootInfo 的 size 之前可能用了表达式（比如 <code>24 + 32 + 8 + ...</code>），这种写法在有人加字段的时候容易漏算，不如直接写死 <code>824</code> 这个最终值——如果有人改了结构体，<code>static_assert</code> 会立即报错。</p><p><strong>实现约束</strong>：修改位置在 <code>boot/boot_info.h</code> 文件底部。<code>MemoryMapEntry</code> 的断言也要加 C/C++ 兼容。不要改变结构体字段的顺序和类型——Bootloader 的汇编代码是按固定偏移量来填写 BootInfo 的，改了字段就全乱套了。</p><p><strong>验证</strong>：编译 Bootloader 和内核都不应该报错。如果你怀疑结构体布局有问题，可以在内核代码里打印 <code>sizeof(BootInfo)</code>，确认输出是 824。</p><h3 id="step-2-在-long-mode-s-中新增高半核页表条目" tabindex="-1">Step 2: 在 long_mode.S 中新增高半核页表条目 <a class="header-anchor" href="#step-2-在-long-mode-s-中新增高半核页表条目" aria-label="Permalink to &quot;Step 2: 在 long_mode.S 中新增高半核页表条目&quot;">​</a></h3><p><strong>目标</strong>：在 <code>setup_page_tables</code> 函数末尾，让 PML4[511] 指向已有的 PDPT，PDPT[510] 指向已有的 PD，建立 0xFFFFFFFF80000000 起始的高半核映射。</p><p><strong>设计思路</strong>：我们在 003 章已经建立了身份映射（PML4[0] -&gt; PDPT[0] -&gt; PD，映射 0 到 2MB 的物理内存）。高半核映射需要复用同一套 PDPT 和 PD——区别仅在于从 PML4 的不同索引进入。具体来说：PML4[511] 里写入&quot;PDPT 物理地址 | 0x03&quot;（Present + Writable），PDPT[510] 里写入&quot;PD 物理地址 | 0x03&quot;。PD[0] 已经在身份映射阶段设好了，它用 2MB 大页映射了物理地址 0~2MB 的范围，而 0x20000 正好落在这个范围内。现在通过 PML4[511] -&gt; PDPT[510] -&gt; PD[0] 这条路径，访问 0xFFFFFFFF80020000 就等于访问物理 0x20000。两条映射指向同一块物理内存，零额外开销。</p><p>你需要确认 <code>PML4_PHYS_ADDR</code>、<code>PDPT_PHYS_ADDR</code>、<code>PD_PHYS_ADDR</code> 这三个常量已经在之前的代码中定义好了（它们的值取决于你把页表放在了哪块低内存区域）。AT&amp;T 汇编语法下，往 PML4 的第 511 个条目（偏移 511<em>8=4088 字节）写入一个 32 位值，用的是 <code>movl %eax, PML4_PHYS_ADDR + (511 * 8)</code>。PDPT[510] 同理，偏移是 510</em>8=4080 字节。</p><p><strong>踩坑预警</strong>：这里只用了 32 位的 <code>movl</code> 来写页表条目，因为我们运行在 32 位兼容模式下（setup_page_tables 是在进 Long Mode 之前调用的），页表物理地址都在 1MB 以内，高 32 位全是 0。如果你手滑用了 <code>movq</code>，在某些汇编器配置下会报错或者生成错误的操作码。另外，条目的 flags 只需要 Present(0x01) + Writable(0x02) = 0x03，不需要设置 Accessed/Dirty 之类的位——那些是 CPU 在运行时自动维护的。</p><p><strong>验证</strong>：这一步暂时没有独立的验证手段，需要等 Step 4 跳转到高半核地址时才能确认映射是否正确。如果你加了错误的映射，跳转时 CPU 会触发 Triple Fault（因为页表找不到对应的物理页），QEMU 会重启。</p><h3 id="step-3-在-stage2-s-中填充-bootinfo" tabindex="-1">Step 3: 在 stage2.S 中填充 BootInfo <a class="header-anchor" href="#step-3-在-stage2-s-中填充-bootinfo" aria-label="Permalink to &quot;Step 3: 在 stage2.S 中填充 BootInfo&quot;">​</a></h3><p><strong>目标</strong>：在 <code>long_mode_entry</code> 标签之后（就是输出 <code>L</code> 字符之后的那段代码），把 BootInfo 的各个字段写到物理地址 0x7000。</p><p><strong>设计思路</strong>：此时我们已经处于 64 位 Long Mode，所有 64 位寄存器都能用了。填写 BootInfo 的过程本质上是一连串的内存写入——先把 <code>%rdi</code> 设为 0x7000（BootInfo 的基地址），然后按偏移量依次填入各个字段。数据来源有两处：帧缓冲信息从物理地址 0x6400 读取（这是之前 VESA 初始化时保存的位置），内存映射从物理地址 0x5000 读取（E820 的输出位置）。</p><p>填写顺序和偏移量必须和 <code>boot_info.h</code> 的结构体定义严格一致。entry_point 是偏移 0（8 字节），写入高半核虚拟地址 0xFFFFFFFF80020000；kernel_phys_base 是偏移 8（8 字节），写入 0x20000；kernel_size 是偏移 16（8 字节），写入内核的最大尺寸（比如 0x68000 = 416KB）。帧缓冲区域稍微复杂一点：0x6400 处存储的格式是 fb_addr（8 字节）在偏移 0，fb_pitch（4 字节）在偏移 8，fb_width（2 字节）在偏移 12，fb_height（2 字节）在偏移 14。但 BootInfo 里的字段顺序是 fb_addr、fb_width、fb_height、fb_pitch、fb_bpp——顺序不一样！所以你需要先从 0x6400 读 fb_addr 写到 BootInfo 偏移 24，再读 pitch 写到偏移 40，读 width（注意要做 16 位到 32 位的零扩展）写到偏移 32，读 height 写到偏移 36。fb_bpp 直接硬编码为 32，写到偏移 44。</p><p>内存映射部分：从 0x5000 读前 4 字节作为 mmap_count 写到 BootInfo 偏移 48，然后从 0x5004 开始复制最多 768 字节（32 条 x 24 字节）到 BootInfo 偏移 56。这里的逐字节拷贝循环可以用 <code>%rsi</code> 指向源地址、<code>%rdx</code> 作为目标偏移、<code>%rcx</code> 作为源偏移、<code>%r8</code> 作为剩余计数——每次读一个字节写到目标，四个计数器各自递增或递减，直到 <code>%r8</code> 归零。</p><p><strong>踩坑预警</strong>：VESA 保存的 width 和 height 是 16 位值（VBE Mode Info 结构就是这样定义的），但 BootInfo 里它们是 32 位的。你需要用零扩展指令（AT&amp;T 语法下是 <code>movzwq</code>，把 16 位零扩展到 64 位然后截取低 32 位写入）来读取它们，不能直接用 <code>movl</code>，否则高位可能带上垃圾数据。另外，帧缓冲字段在 BootInfo 里的排列顺序和 0x6400 处的 VESA 缓冲区格式不一样——pitch 在 VESA 缓冲区是第二个字段，但在 BootInfo 里是第四个。照着 VESA 的顺序抄到 BootInfo 里就会写到错误的偏移，后续内核拿到的帧缓冲参数全是乱的。</p><p><strong>验证</strong>：暂时没有独立的运行验证，需要配合 Step 4 的跳转一起验证。但你可以通过 GDB 在跳转前检查 0x7000 处的内存内容——比如 <code>x/gx 0x7000</code> 应该看到 entry_point 为 0xFFFFFFFF80020000，<code>x/gx 0x7008</code> 应该看到 0x20000。</p><h3 id="step-4-跳转到-mini-kernel-的高半核入口" tabindex="-1">Step 4: 跳转到 Mini Kernel 的高半核入口 <a class="header-anchor" href="#step-4-跳转到-mini-kernel-的高半核入口" aria-label="Permalink to &quot;Step 4: 跳转到 Mini Kernel 的高半核入口&quot;">​</a></h3><p><strong>目标</strong>：在 BootInfo 填充完成后，向 debugcon 输出 <code>J</code> 字符作为&quot;即将跳转&quot;的标记，然后把 BootInfo 地址放进 <code>%rdi</code>（System V AMD64 ABI 的第一个参数寄存器），把内核入口地址放进 <code>%rax</code>，执行间接跳转。</p><p><strong>设计思路</strong>：这是 Bootloader 使命的终点。按照 System V AMD64 ABI 的调用约定，函数的第一个参数通过 <code>%rdi</code> 传递。虽然这里不是标准的函数调用（而是 <code>jmp</code> 跳转），但我们遵循同样的约定——把 BootInfo 的物理地址 0x7000 放进 <code>%rdi</code>，让内核入口代码知道从哪里读取引导信息。内核入口地址是 0xFFFFFFFF80020000（高半核地址），放进 <code>%rax</code> 后用 <code>jmp *%rax</code> 做间接跳转。这里用 <code>jmp</code> 而不是 <code>call</code>，是因为我们不打算返回——Bootloader 的生命到此结束。跳转之后 bootloader 的代码就永远不会回来了，所以用 <code>jmp</code> 在语义上更准确——<code>call</code> 会把返回地址压栈白白浪费 8 字节。</p><p>这个跳转跨越了虚拟地址空间：从 identity mapping 区域（bootloader 的代码还在低地址执行）跳到 higher-half 区域（内核的 <code>_start</code> 在 0xFFFFFFFF80020000）。因为两条映射指向同一套物理页表条目，CPU 的 TLB 能够正确地翻译这个地址，跳转不会触发 Page Fault。</p><p>输出 <code>J</code>（0x4A）到 debugcon 是为了在调试日志中留下明确的分界点。如果 QEMU 在 <code>J</code> 之后立刻 Triple Fault 重启了，说明要么高半核页表映射有问题，要么内核入口代码本身有 bug。如果 <code>J</code> 之后什么输出都没有（QEMU 挂起），说明内核入口可能卡在了某个死循环或者 <code>hlt</code> 上。有了这个 <code>J</code> 标记，排查范围就缩小了很多。</p><p><strong>踩坑预警</strong>：这里有一个非常容易犯的错误——<code>jmp *%rax</code> 是 AT&amp;T 语法的间接跳转，星号不能省。如果你写成了 <code>jmp %rax</code>，汇编器会把它解释成跳转到 <code>%rax</code> 里的值所代表的相对偏移，而不是跳转到 <code>%rax</code> 指向的地址。这两种解释的结果天差地别——前者大概率跳到了一个完全错误的位置。另外，跳转之前别忘了再次把 <code>%rdi</code> 设为 0x7000——前面填充 BootInfo 的过程中你可能改了 <code>%rdi</code>（毕竟你拿它当目标基地址用了），需要在跳转前重新设置。</p><p><strong>验证</strong>：这是本篇最重要的验证步骤。完整构建并运行 QEMU 后，debugcon 日志应该出现字符序列 <code>OPLJ</code>——<code>O</code> 是 MBR 加载 Stage2，<code>P</code> 是保护模式切换，<code>L</code> 是 Long Mode 进入，<code>J</code> 是跳转到 Mini Kernel。如果 <code>J</code> 之后紧跟着 <code>1</code>、<code>2</code>、<code>3</code>、<code>4</code> 这几个字符，说明内核入口代码（boot.S）正在执行——那是下一篇的内容了。</p><h2 id="构建配置变更-debugcon-全局启用" tabindex="-1">构建配置变更：debugcon 全局启用 <a class="header-anchor" href="#构建配置变更-debugcon-全局启用" aria-label="Permalink to &quot;构建配置变更：debugcon 全局启用&quot;">​</a></h2><p>在动手构建之前，有一个小但关键的配置变更需要先做。<code>cmake/qemu.cmake</code> 需要把 debugcon 相关的 QEMU 参数从 <code>QEMU_DEBUG_FLAGS</code>（只在 debug 模式启用）移到 <code>QEMU_COMMON_FLAGS</code>（所有模式都启用）。</p><p>原因是这样的：之前 debugcon 只在 <code>make run-debug</code> 下启用，正常 <code>make run</code> 下是不启用的。但从 004C 开始，内核的 <code>boot.S</code> 和 <code>main.cpp</code> 都依赖 debugcon 输出来验证执行状态——<code>OPLJ123G4===CPPGC1V123B===END</code> 这串字符全部通过 <code>outb</code> 写到 0xE9 端口。如果正常模式下不启用 debugcon，<code>outb %al, $0xE9</code> 会变成一个空操作，你什么都看不到。</p><p>具体来说，<code>QEMU_COMMON_FLAGS</code> 需要包含 <code>-debugcon file:debug.log -global isa-debugcon.iobase=0xe9</code> 这两个参数。<code>-global isa-debugcon.iobase=0xe9</code> 把 debugcon 设备的 I/O 端口绑定到 0xE9，QEMU 的 isa-debugcon 设备默认端口就是 0xE9，但显式指定可以避免未来的默认值变更导致问题。<code>-debugcon file:debug.log</code> 指定 debugcon 输出写到 <code>debug.log</code> 文件。</p><h2 id="构建与运行" tabindex="-1">构建与运行 <a class="header-anchor" href="#构建与运行" aria-label="Permalink to &quot;构建与运行&quot;">​</a></h2><p>配置变更完成后，在项目根目录执行完整构建并运行。构建命令和前面几章一样——CMake 配置、编译、<code>make run</code>。</p><p>QEMU 启动后，debugcon 日志（<code>debug.log</code> 文件）应该包含以下字符序列：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>OPLJ123G4===CPPGC1V123B===END</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>其中 <code>OPLJ</code> 是本篇关注的部分——<code>J</code> 的出现意味着 Bootloader 成功填充了 BootInfo 并完成了高半核跳转。后面从 <code>1</code> 开始的字符是 Mini Kernel 的入口代码和 C++ 运行时产生的，下一篇会详细讲解。</p><p>如果你只看到了 <code>OPL</code> 而没有 <code>J</code>，说明跳转代码没有执行到。检查 <code>stage2.S</code> 中 <code>long_mode_entry</code> 之后的代码是否被正确汇编和链接。如果看到了 <code>J</code> 但之后 QEMU 立刻重启（Triple Fault），说明高半核页表映射可能有问题——这时候就需要动用下面的调试技巧了。</p><h2 id="调试技巧" tabindex="-1">调试技巧 <a class="header-anchor" href="#调试技巧" aria-label="Permalink to &quot;调试技巧&quot;">​</a></h2><p>这一章涉及三个容易出错的环节：页表映射、BootInfo 字段填充、跳转本身。下面按场景给出排查思路。</p><h3 id="场景-1-opl-之后没有-j" tabindex="-1">场景 1：OPL 之后没有 J <a class="header-anchor" href="#场景-1-opl-之后没有-j" aria-label="Permalink to &quot;场景 1：OPL 之后没有 J&quot;">​</a></h3><p>这是最常见的问题——BootInfo 填充代码或跳转代码没有执行到。可能的原因包括：<code>long_mode_entry</code> 之后的代码没有被正确汇编（检查链接脚本是否包含了 stage2.S 的 Long Mode 部分）、BootInfo 填充过程中某条指令触发了异常（比如访问了无效地址）。</p><p>排查方法是在 GDB 中在 <code>long_mode_entry</code> 后面设断点，单步执行 BootInfo 填充代码，看看卡在哪一步。</p><h3 id="场景-2-j-之后-triple-fault" tabindex="-1">场景 2：J 之后 Triple Fault <a class="header-anchor" href="#场景-2-j-之后-triple-fault" aria-label="Permalink to &quot;场景 2：J 之后 Triple Fault&quot;">​</a></h3><p>这说明高半核页表映射有问题。在 GDB 中可以在跳转前检查页表内容：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(gdb) x/gx 0x1000 + 511*8</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>PML4 的物理地址是 0x1000，第 511 个条目的偏移是 511<em>8=4088。你应该看到一个有效的 PDPT 物理地址（0x2000）加上 0x03 标志位。PDPT[510] 同理，检查 0x2000 + 510</em>8 处是否为 PD 物理地址（0x3000）加 0x03。如果那里是 0 或者是一个看起来不像物理地址的值，说明 <code>setup_page_tables</code> 的那段新增代码没有正确执行。</p><p>另外一个容易忽视的点是：页表条目是 64 位的，而我们在 32 位模式下只写了低 32 位。如果你的汇编器没有自动把高 32 位清零，页表条目的高半部分可能带着垃圾数据。实际代码中需要显式用 <code>movl $0, addr + 4</code> 把高 32 位清零——这一点在 <code>long_mode.S</code> 的源码中已经处理了，但如果你是自己从头写的，很容易漏掉。</p><h3 id="场景-3-bootinfo-字段值不对" tabindex="-1">场景 3：BootInfo 字段值不对 <a class="header-anchor" href="#场景-3-bootinfo-字段值不对" aria-label="Permalink to &quot;场景 3：BootInfo 字段值不对&quot;">​</a></h3><p>在跳转之前（<code>jmp *%rax</code> 的前一条指令设断点），用 GDB 检查 0x7000 处的内容：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(gdb) x/4gx 0x7000</span></span>
<span class="line"><span>(gdb) x/6wx 0x7020</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>第一条命令查看 entry_point、kernel_phys_base、kernel_size、fb_addr。第二条查看 fb_width、fb_height、fb_pitch、fb_bpp 等。所有值应该合理——entry_point 应该是 0xFFFFFFFF80020000（小端序，实际内存中是 <code>00 00 02 80 FF FF FF FF</code>），fb_width 应该是你设置的 VESA 分辨率宽度（比如 1024 = 0x400）。</p><p>如果 fb_width 或 fb_height 的值看起来异常大（比如几万），很可能是在从 0x6400 读取 16 位值时没有做零扩展——<code>movl</code> 读 16 位会把高 16 位也带进来，导致读到垃圾数据。检查你的代码是否使用了 <code>movzwq</code>（零扩展 16 位到 64 位）来读取 width 和 height。</p><h3 id="用-qemu-monitor-查看页表" tabindex="-1">用 QEMU Monitor 查看页表 <a class="header-anchor" href="#用-qemu-monitor-查看页表" aria-label="Permalink to &quot;用 QEMU Monitor 查看页表&quot;">​</a></h3><p>QEMU 的 Monitor 模式下可以直接查看 CPU 的页表映射：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(qemu) info mem</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这个命令会列出所有已映射的虚拟地址范围。你应该能看到两行：0x0000000000000000 到 0x0000000000200000 的身份映射，以及 0xFFFFFFFF80000000 到 0xFFFFFFFF80200000 的高半核映射。如果只看到身份映射那一行，说明 PML4[511] 或 PDPT[510] 没有正确设置。</p><h2 id="设计决策" tabindex="-1">设计决策 <a class="header-anchor" href="#设计决策" aria-label="Permalink to &quot;设计决策&quot;">​</a></h2><h3 id="为什么-bootinfo-使用固定物理地址" tabindex="-1">为什么 BootInfo 使用固定物理地址 <a class="header-anchor" href="#为什么-bootinfo-使用固定物理地址" aria-label="Permalink to &quot;为什么 BootInfo 使用固定物理地址&quot;">​</a></h3><p>BootInfo 放在固定物理地址 0x7000 而不是动态协商。固定地址在调试时有巨大的优势——你可以在 QEMU monitor 中直接 <code>xp /824bx 0x7000</code> 查看完整的 BootInfo 内容，不需要先找指针再间接寻址。而且 Cinux 的 bootloader 是自写的，bootloader 和内核之间不存在&quot;多个 bootloader 实现&quot;的兼容性问题。如果是 GRUB 加载内核，那就得用 Multiboot 规范的动态地址方案——bootloader 把信息结构体的物理地址放在 <code>%ebx</code> 中传递，内核根据 <code>%ebx</code> 的值动态找到结构体。</p><h3 id="为什么高半核映射复用-pd-条目" tabindex="-1">为什么高半核映射复用 PD 条目 <a class="header-anchor" href="#为什么高半核映射复用-pd-条目" aria-label="Permalink to &quot;为什么高半核映射复用 PD 条目&quot;">​</a></h3><p>高半核映射复用了 identity mapping 的 PD 条目，而不是分配独立的页表。原因是 bootloader 阶段分配的固定页表内存（0x1000~0x3FFF）已经捉襟见肘——总共只有 3 个 4KB 页，分别给了 PML4、PDPT 和 PD。如果要建立独立的 PDPT 和 PD，还需要额外的 8KB 物理内存。更重要的是，bootloader 的页表只是临时的，内核启动后会建立自己的正式页表。启动阶段的简洁性比安全性更重要。等到内核的物理内存管理器上线后，可以在内核初始化阶段分配新的页表页面，把高半核映射独立出来，然后取消 identity mapping。</p><h2 id="tag-边界说明" tabindex="-1">Tag 边界说明 <a class="header-anchor" href="#tag-边界说明" aria-label="Permalink to &quot;Tag 边界说明&quot;">​</a></h2><p>在继续动手之前，确认一下 004C 和 004A/004B 的分工边界。004A 负责的是 Real Mode 下的两件事——E820 内存探测（结果存在 0x5000）和从磁盘把 Mini Kernel 读到 0x20000。004B 负责的是 BootInfo 结构定义、磁盘读取从 4KB 升级到 416KB（分块循环）、以及 flat binary 构建系统。004C 的上篇（本篇）负责 Long Mode 阶段的三件事——高半核页表映射、BootInfo 填充、跳转到内核。004C 的下篇负责内核侧——SSE 启用、栈设置、BSS 清除、全局构造函数调用、C++ 特性验证。这个分工确保了每个 tag 只关注一个清晰的阶段：004A 是 Real Mode 数据准备，004B 是结构定义和磁盘加载，004C 是 Long Mode 交接和内核启动。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>要点</th></tr></thead><tbody><tr><td>BootInfo 结构</td><td>824 字节 packed 结构，固定存放于物理 0x7000，Bootloader 和内核共用定义</td></tr><tr><td>BootInfo 字段顺序</td><td>entry_point(8B) + phys_base(8B) + size(8B) + fb_addr(8B) + fb_width(4B) + fb_height(4B) + fb_pitch(4B) + fb_bpp(4B) + mmap_count(4B) + _pad(4B) + mmap[32](768B)</td></tr><tr><td>C/C++ 兼容 static_assert</td><td><code>#if defined(__cplusplus)</code> 分支选择 <code>static_assert</code> 和 <code>_Static_assert</code></td></tr><tr><td>高半核地址</td><td>0xFFFFFFFF80020000 = 0xFFFFFFFF80000000 + 0x20000，PML4[511] -&gt; PDPT[510] -&gt; PD[0]</td></tr><tr><td>双重映射</td><td>同一 PD[0] 条目（0~2MB）同时服务身份映射和高半核映射，零额外物理页开销</td></tr><tr><td>System V AMD64 ABI 调用约定</td><td>第一个参数通过 <code>%rdi</code> 传递，BootInfo 地址 = 0x7000</td></tr><tr><td>间接跳转</td><td>AT&amp;T 语法 <code>jmp *%rax</code>，星号不能省略</td></tr><tr><td>本篇验证字符</td><td><code>OPLJ</code>——<code>J</code> 表示 Bootloader 成功跳转到 Mini Kernel</td></tr><tr><td>debugcon 全局启用</td><td>将 <code>-debugcon file:debug.log</code> 从 DEBUG_FLAGS 移到 COMMON_FLAGS，确保 <code>make run</code> 也能看到 debugcon 输出</td></tr><tr><td>004C 边界</td><td>004A=E820+磁盘读取(Real Mode), 004B=BootInfo定义+416KB加载, 004C=高半核映射+填充+跳转(Long Mode)+内核启动</td></tr><tr><td>高半核 PD 索引</td><td>实际映射 0x20000 的是 PD[0]（0~2MB），而非 PD[1]——因为 0x20000 在 0~2MB 范围内</td></tr><tr><td>Canonical Address</td><td>0xFFFFFFFF80020000 的 bit 47=1，bits 63:48 全 1，符合 canonical 约束</td></tr><tr><td>debugcon 端口</td><td>I/O 端口 0xE9，QEMU isa-debugcon 设备，<code>-global isa-debugcon.iobase=0xe9</code></td></tr></tbody></table>`,88)])])}const F=e(c,[["render",n]]);export{h as __pageData,F as default};
